const keywords = [
  'Quantitative Developer',
  'Quant Developer',
  'Algorithmic Trading Engineer',
  'Trading Systems Engineer',
  'Systematic Trader Developer',
  'Options Quant',
  'Derivatives Quant',
  'Volatility Quant',
  'Index Options Trader Quant',
  'Execution Engineer Trading',
  'Market Microstructure Researcher',
  'Market Making Engineer'
];

const location = $env.LINKEDIN_JOB_LOCATION || 'Berlin, Germany';
const publishedAt = $env.LINKEDIN_PUBLISHED_AT || 'r604800';
const geoId = $env.LINKEDIN_GEO_ID || '';
const maxKeywords = Number($env.LINKEDIN_MAX_KEYWORDS_PER_RUN || keywords.length);
const selectedKeywords = keywords.slice(0, maxKeywords);

function searchUrl(keyword) {
  const parts = [
    'f_TPR=' + encodeURIComponent(publishedAt),
    'keywords=' + encodeURIComponent(keyword)
  ];
  if (geoId) parts.push('geoId=' + encodeURIComponent(geoId));
  return 'https://www.linkedin.com/jobs/search/?' + parts.join('&');
}

return [
  {
    json: {
      actorInput: {
        enrichCompanyData: false,
        keyword: selectedKeywords,
        location,
        publishedAt,
        resumeKeywords: [
          { keyword: 'Python' },
          { keyword: 'C++' },
          { keyword: 'Quantitative Research', aliases: ['Quant Research'] },
          { keyword: 'Algorithmic Trading', aliases: ['Algo Trading'] },
          { keyword: 'Options', aliases: ['Derivatives', 'Volatility'] },
          { keyword: 'Market Microstructure' },
          { keyword: 'Low Latency', aliases: ['Low-Latency'] },
          { keyword: 'Market Making' },
          { keyword: 'Execution' }
        ],
        saveOnlyUniqueItems: true,
        startUrls: selectedKeywords.map((keyword) => ({ url: searchUrl(keyword) }))
      }
    }
  }
];

function stableId(value) {
  const text = String(value || '');
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = ((hash << 5) - hash + text.charCodeAt(index)) | 0;
  }
  return 'id_' + Math.abs(hash).toString(36) + '_' + text.length.toString(36);
}

function asText(value) {
  if (value == null) return '';
  if (Array.isArray(value)) return value.map(asText).filter(Boolean).join(', ');
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value);
}

function pick(job, keys) {
  for (const key of keys) {
    if (job[key] != null && job[key] !== '') return job[key];
  }
  return '';
}

const rows = [];

for (const item of items) {
  const job = item.json;
  const sourceUrl = asText(pick(job, ['jobUrl', 'url', 'link', 'linkedinUrl', 'externalUrl', 'applyUrl']));
  const title = asText(pick(job, ['title', 'jobTitle', 'position']));
  const companyName = asText(pick(job, ['companyName', 'company', 'organization']));
  const location = asText(pick(job, ['location', 'jobLocation', 'formattedLocation']));
  const description = asText(pick(job, ['description', 'jobDescription', 'descriptionText', 'text']));
  const employmentType = asText(pick(job, ['employmentType', 'jobType', 'contractType']));
  const postedAt = asText(pick(job, ['publishedAt', 'postedAt', 'listedAt', 'createdAt', 'date']));
  const salary = asText(pick(job, ['salary', 'salaryInfo', 'compensation']));
  const workplaceType = asText(pick(job, ['workplaceType', 'workType', 'remoteType']));
  const seniority = asText(pick(job, ['seniorityLevel', 'seniority', 'experienceLevel']));
  const applyType = asText(pick(job, ['applyType', 'applicationType']));
  const companyUrl = asText(pick(job, ['companyUrl', 'companyLinkedinUrl', 'companyLinkedInUrl']));
  const keyword = item.pairedItem ? $items('Build LinkedIn Apify Inputs')[item.pairedItem.item]?.json.keyword : '';
  const uid = pick(job, ['id', 'jobId', 'urn', 'uid']) || sourceUrl || (companyName + '|' + title + '|' + location + '|' + postedAt);

  const details = [
    description,
    salary ? 'Salary: ' + salary : '',
    workplaceType ? 'Workplace type: ' + workplaceType : '',
    seniority ? 'Seniority: ' + seniority : '',
    applyType ? 'Apply type: ' + applyType : '',
    companyUrl ? 'Company URL: ' + companyUrl : '',
    keyword ? 'Matched keyword: ' + keyword : ''
  ].filter(Boolean).join('\\n\\n');

  rows.push({
    json: {
      external_id: stableId(uid),
      source: 'Apify LinkedIn',
      source_url: sourceUrl,
      title,
      company_name: companyName || 'LinkedIn Company',
      location,
      region: location || 'LinkedIn',
      description: details,
      employment_type: employmentType,
      salary_min: null,
      salary_max: null,
      currency: '',
      posted_at: postedAt || null,
      discovered_at: new Date().toISOString(),
      stage: 'Discovered',
      category: 'LinkedIn Job',
      skills: asText(pick(job, ['skills', 'jobSkills'])),
      budget: salary,
      matched_keyword: keyword,
      workplace_type: workplaceType,
      seniority,
      apply_type: applyType,
      company_url: companyUrl,
      raw_payload: job
    }
  });
}

const seen = new Set();
return rows.filter((row) => {
  const key = row.json.external_id;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return items.map((item) => ({
  json: {
    opportunity: item.json,
    openaiBody: {
      model: $env.OPENAI_SCORING_MODEL || 'gpt-5-mini',
      input: [
        { role: 'system', content: 'You evaluate LinkedIn job opportunities for Farshad, an advanced quantitative researcher and AI/ML engineer. Return strict JSON only.' },
        { role: 'user', content: 'Evaluate this LinkedIn job opportunity. Favor quant developer, trading systems, algorithmic trading, options, derivatives, volatility, index options, execution engineering, market microstructure, market making, low-latency Python/C++, and financial infrastructure roles. Return JSON with score, priority, strengths, risks, suggested_positioning, next_action, and reasoning. Opportunity: ' + JSON.stringify(item.json) }
      ],
      text: { format: { type: 'json_schema', name: 'opportunity_score', schema: { type: 'object', additionalProperties: false, properties: { score: { type: 'number' }, priority: { type: 'string' }, strengths: { type: 'array', items: { type: 'string' } }, risks: { type: 'array', items: { type: 'string' } }, suggested_positioning: { type: 'string' }, next_action: { type: 'string' }, reasoning: { type: 'string' } }, required: ['score', 'priority', 'strengths', 'risks', 'suggested_positioning', 'next_action', 'reasoning'] } } }
    }
  }
}));

function findText(value) {
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) {
    for (const entry of value) {
      const found = findText(entry);
      if (found) return found;
    }
    return '';
  }
  if (value && typeof value === 'object') {
    if (typeof value.output_text === 'string') return value.output_text;
    if (typeof value.text === 'string') return value.text;
    if (typeof value.content === 'string') return value.content;
    for (const key of ['output', 'content', 'message']) {
      const found = findText(value[key]);
      if (found) return found;
    }
  }
  return '';
}

return items.map((item) => {
  const original = item.pairedItem ? $items('Build OpenAI LinkedIn Request')[item.pairedItem.item].json.opportunity : {};
  const text = findText(item.json) || '{}';
  let score = {};
  try { score = typeof text === 'string' ? JSON.parse(text) : text; }
  catch (error) { score = { score: 0, priority: 'Low', strengths: [], risks: ['OpenAI response could not be parsed'], suggested_positioning: '', next_action: 'Review manually', reasoning: error.message }; }
  return { json: { ...original, score: score.score ?? 0, priority: score.priority || 'Low', strengths: Array.isArray(score.strengths) ? score.strengths.join('\n') : String(score.strengths || ''), risks: Array.isArray(score.risks) ? score.risks.join('\n') : String(score.risks || ''), positioning: score.suggested_positioning || '', next_action: score.next_action || '', reasoning: score.reasoning || '', stage: Number(score.score) >= 70 ? 'Evaluated' : 'Archived' } };
});
